61	  pv: Extract<Element, { kind: 'plan_view' }>,
62	  elementsById: Record<string, Element>,
63	): string {
64	  const parts = [`plan_view (${pv.name})`];
65	  parts.push(planLevelEvidenceToken(elementsById, pv.levelId));
66	  parts.push(`discipline: ${pv.discipline ?? 'architecture'}`);
67	  const tid = pv.viewTemplateId;
68	  if (tid) {
69	    const t = elementsById[tid];
70	    parts.push(t?.kind === 'view_template' ? `template: ${t.name}` : `templateRef: ${tid}`);
71	  }
72	  parts.push(planViewProjectBrowserEvidenceLine(elementsById, pv.id));
73	  const h = planViewBrowserHierarchyState(elementsById, pv.id);
74	  parts.push(
75	    `catSrc: def=${h.categoryDefaultCount} tmpl=${h.categoryTemplateCount} pv=${h.categoryPlanViewCount}`,
76	  );
77	  parts.push(`tagSrc: o=${h.openingTagSource} r=${h.roomTagSource}`);
78	  return parts.join(' · ');
79	}
