586	      {collapsed ? null : (
587	        <ul className="space-y-0.5">
588	          {links.map((l) => {
589	            const cur = linkSourceRevisions[l.sourceModelId];
590	            const pinned = l.sourceModelRevision ?? null;
591	            const drift = pinned != null && typeof cur === 'number' ? Math.max(0, cur - pinned) : 0;
592	            const hidden = !!l.hidden;
593	            return (
594	              <li
595	                key={l.id}
596	                data-testid={`project-browser-links-row-${l.id}`}
597	                className="flex items-center gap-2 px-2 py-0.5 text-[10px]"
598	              >
599	                <button
600	                  type="button"
601	                  disabled={pending === l.id}
602	                  data-testid={`project-browser-links-eye-${l.id}`}
603	                  onClick={() => void toggleHidden(l)}
604	                  title={hidden ? 'Show link in viewport' : 'Hide link in viewport'}
605	                  className="rounded border border-border px-1 text-[10px] hover:bg-surface-strong disabled:opacity-50"
606	                >
607	                  {hidden ? '◌' : '●'}
608	                </button>
609	                <button
610	                  type="button"
611	                  className="flex-1 text-left"
612	                  onClick={() => useBimStore.getState().select(l.id)}
613	                  title={`Select link_model ${l.name}`}
614	                >
615	                  <span className="text-muted">link_model ·</span> {l.name}
616	                </button>
617	                {drift > 0 ? (
618	                  <span
619	                    data-testid={`project-browser-links-drift-${l.id}`}
620	                    title={`Source advanced by ${drift} commit${drift === 1 ? '' : 's'}`}
621	                    style={{
622	                      background: '#facc15',
623	                      color: '#1f2937',
624	                      padding: '0 4px',
625	                      borderRadius: 3,
626	                      fontSize: 9,
627	                      fontWeight: 600,
628	                    }}
629	                  >
630	                    +{drift}
631	                  </span>
632	                ) : null}
633	              </li>
634	            );
635	          })}
636	        </ul>
637	      )}
638	    </div>
639	  );
640	}
